if (historyIterator.previousIndex() != -1) {
 throw new AssertionError();
 }
 System.out.println("Going forward:");
 while (historyIterator.hasNext()) {
 System.out.printf("index: %d %s%n",
 historyIterator.nextIndex(), historyIterator.next());
 }
 }
 }

